import{_ as e,o as n,c as d,ag as o}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"Launch Context","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/launch-context.md","filePath":"admin-ui/launch-context.md"}'),a={name:"admin-ui/launch-context.md"};function r(c,t,i,s,h,l){return n(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="launch-context" tabindex="-1">Launch Context <a class="header-anchor" href="#launch-context" aria-label="Permalink to &quot;Launch Context&quot;">​</a></h1><p>Launch Context management configures SMART App Launch context parameters per user. These values are injected into access tokens as claims, enabling SMART apps to receive patient, encounter, and other context on launch.</p><h2 id="accessing" tabindex="-1">Accessing <a class="header-anchor" href="#accessing" aria-label="Permalink to &quot;Accessing&quot;">​</a></h2><p>Navigate to <strong>SMART Config</strong> in the admin sidebar, then select the <strong>Launch Context</strong> tab. The tab has three nested views:</p><h2 id="context-overview" tabindex="-1">Context Overview <a class="header-anchor" href="#context-overview" aria-label="Permalink to &quot;Context Overview&quot;">​</a></h2><p>Displays all users who have launch context attributes configured, showing:</p><ul><li>Username and user ID</li><li>Assigned fhirUser reference</li><li>Patient and encounter in context</li><li>Additional context (intent, tenant, fhirContext)</li></ul><h2 id="template-library" tabindex="-1">Template Library <a class="header-anchor" href="#template-library" aria-label="Permalink to &quot;Template Library&quot;">​</a></h2><p>Pre-built launch context templates for common clinical workflows:</p><ul><li><strong>EHR Launch with Patient</strong> — sets patient context for EHR-launched apps</li><li><strong>Standalone Patient Access</strong> — configures patient self-access context</li><li><strong>Practitioner with Encounter</strong> — sets both patient and encounter context</li><li>Custom templates for specific workflow needs</li></ul><h2 id="user-contexts" tabindex="-1">User Contexts <a class="header-anchor" href="#user-contexts" aria-label="Permalink to &quot;User Contexts&quot;">​</a></h2><p>Configure launch context attributes for individual users:</p><h3 id="core-smart-context-attributes" tabindex="-1">Core SMART Context Attributes <a class="header-anchor" href="#core-smart-context-attributes" aria-label="Permalink to &quot;Core SMART Context Attributes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Attribute</th><th>Token Claim</th><th>Description</th></tr></thead><tbody><tr><td><strong>fhirUser</strong></td><td><code>fhirUser</code></td><td>FHIR resource representing the user (e.g., <code>Practitioner/123</code>, <code>Patient/456</code>)</td></tr><tr><td><strong>Patient</strong></td><td><code>smart_patient</code></td><td>Patient ID in context for patient-scoped launches</td></tr><tr><td><strong>Encounter</strong></td><td><code>smart_encounter</code></td><td>Encounter ID in context</td></tr><tr><td><strong>fhirContext</strong></td><td><code>smart_fhir_context</code></td><td>Array of FHIR resource references providing additional context</td></tr></tbody></table><h3 id="extended-attributes" tabindex="-1">Extended Attributes <a class="header-anchor" href="#extended-attributes" aria-label="Permalink to &quot;Extended Attributes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Attribute</th><th>Token Claim</th><th>Description</th></tr></thead><tbody><tr><td><strong>Intent</strong></td><td><code>smart_intent</code></td><td>Workflow intent string (e.g., <code>reconcile-medications</code>, <code>order-sign</code>)</td></tr><tr><td><strong>Need Patient Banner</strong></td><td><code>smart_need_patient_banner</code></td><td>Whether the app should display a patient identification banner</td></tr><tr><td><strong>Style URL</strong></td><td><code>smart_style_url</code></td><td>URL to CSS stylesheet for app branding</td></tr><tr><td><strong>Tenant</strong></td><td><code>smart_tenant</code></td><td>Tenant identifier for multi-tenant deployments</td></tr></tbody></table><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/launch-contexts/</code></td><td>List all users with launch context</td></tr><tr><td><code>POST</code></td><td><code>/admin/launch-contexts/:userId/fhir-user/:fhirUserId</code></td><td>Set fhirUser for a user</td></tr><tr><td><code>POST</code></td><td><code>/admin/launch-contexts/:userId/patient/:patientId</code></td><td>Set patient context</td></tr><tr><td><code>POST</code></td><td><code>/admin/launch-contexts/:userId/encounter/:encounterId</code></td><td>Set encounter context</td></tr><tr><td><code>POST</code></td><td><code>/admin/launch-contexts/:userId/fhir-context</code></td><td>Set fhirContext array</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/fhir-user</code></td><td>Remove fhirUser</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/patient</code></td><td>Remove patient context</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/encounter</code></td><td>Remove encounter context</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/fhir-context</code></td><td>Remove fhirContext</td></tr><tr><td><code>PUT</code></td><td><code>/admin/launch-contexts/:userId/intent</code></td><td>Set intent</td></tr><tr><td><code>PUT</code></td><td><code>/admin/launch-contexts/:userId/need-patient-banner</code></td><td>Set need_patient_banner</td></tr><tr><td><code>PUT</code></td><td><code>/admin/launch-contexts/:userId/smart-style-url</code></td><td>Set style URL</td></tr><tr><td><code>PUT</code></td><td><code>/admin/launch-contexts/:userId/tenant</code></td><td>Set tenant</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/intent</code></td><td>Remove intent</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/need-patient-banner</code></td><td>Remove need_patient_banner</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/smart-style-url</code></td><td>Remove style URL</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/launch-contexts/:userId/tenant</code></td><td>Remove tenant</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Launch context values are stored as Keycloak user attributes. When a user authenticates and receives a token, Keycloak&#39;s SMART scope mappers read these attributes and inject them as token claims. SMART apps then receive these claims in the token response or via introspection.</p><p>For example, setting <code>patient=Patient/123</code> for a user means any SMART app launched with <code>launch/patient</code> scope will receive <code>&quot;patient&quot;: &quot;Patient/123&quot;</code> in the token response.</p><p>See <a href="./scope-management">Scope Management</a> for configuring the SMART scope mappers that read these attributes.</p>',22)])])}const m=e(a,[["render",r]]);export{p as __pageData,m as default};
